module top_module(
    input [1:0] in,
    input clk,
    output reg [3:0] out
);reg [3:0] inverted_out;

always @(*) begin
    case(in)
        2'b00: inverted_out = 4'b0001;
        2'b01: inverted_out = 4'b0010;
        2'b10: inverted_out = 4'b0100;
        2'b11: inverted_out = 4'b1000;
        default: inverted_out = 4'b0000; // default case to avoid latch inference
    endcase
end

always @(posedge clk) begin
    out <= inverted_out;
end

endmodule
